// Unpack Notion property objects into flat $json.* references.
// ── Adjust property key strings to match your actual Clients DB column names ──
const p = $input.first().json.properties ?? {};

const text   = prop => prop?.rich_text?.[0]?.plain_text ?? prop?.title?.[0]?.plain_text ?? '';
const sel    = prop => prop?.select?.name ?? '';
const em     = prop => prop?.email ?? '';
const multi  = prop => (prop?.multi_select ?? []).map(s => s.name);
const dt     = prop => prop?.date?.start ?? '';

const c = {
  page_id:          $input.first().json.id,
  page_url:         $input.first().json.url,
  company_name:     text(p['Name'] ?? p['Company']),
  contact_name:     text(p['Contact Name']),
  contact_email:    em(p['Contact Email']),
  team_size:        sel(p['Team Size']),
  pain_primary:     sel(p['Pain Point']),
  cloud:            sel(p['Cloud']),
  compliance:       sel(p['Compliance']),
  compliance_detail:text(p['Compliance Detail'] ?? p['Off-limits']),
  automation:       text(p['Automation']),
  tools_crm:        text(p['Tools — CRM']),
  tools_pm:         text(p['Tools — PM']),
  tools_comms:      text(p['Tools — Comms']),
  tools_ads:        text(p['Tools — Ads'] ?? p['Tools — Marketing']),
  tools_email:      text(p['Tools — Email']),
  tools_billing:    text(p['Tools — Billing']),
  tools_data:       text(p['Tools — Data']),
  tools_other:      text(p['Tools — Other']),
  off_limits:       text(p['Off-limits']),
  outcome_30d:      text(p['Outcome 30d'] ?? p['Outcome']),
  submitted_at:     dt(p['Submitted At']),
  tags:             multi(p['Tags']),
};

return [{ json: c }];

const c = $input.first().json;

const toolsStr = [
  c.tools_crm     && `CRM: ${c.tools_crm}`,
  c.tools_pm      && `Project mgmt: ${c.tools_pm}`,
  c.tools_comms   && `Comms: ${c.tools_comms}`,
  c.tools_ads     && `Marketing/ads: ${c.tools_ads}`,
  c.tools_email   && `Email automation: ${c.tools_email}`,
  c.tools_billing && `Billing: ${c.tools_billing}`,
  c.tools_data    && `Data/storage: ${c.tools_data}`,
  c.automation    && `Automation platforms: ${c.automation}`,
  c.tools_other   && `Other: ${c.tools_other}`,
].filter(Boolean).join('\n');

// Company slug for env names (lowercase, alphanumeric+hyphen)
const slug = (c.company_name || 'client').toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '').slice(0, 20);

const prompt = `You are an expert automation and ops architect. Based on this client intake data, generate a complete blueprint specification as structured JSON. Be specific and actionable — this directly drives an infra plan and client deliverable.

INTAKE DATA:
Company: ${c.company_name}
Team size: ${c.team_size}
Primary pain: ${c.pain_primary}
Desired 30-day outcome: ${c.outcome_30d || 'not provided'}
Security/compliance tier: ${c.compliance}
Cloud provider: ${c.cloud}
Off-limits systems: ${c.off_limits || 'none stated'}
Compliance detail: ${c.compliance_detail || 'none'}

Tools stack:\n${toolsStr || 'not specified'}

Return ONLY a raw JSON object (no markdown fences, no explanation). Use this exact schema:
{
  "stack_maturity": "Ad-hoc | Emerging | Structured",
  "primary_focus": ["one or more of: Reporting, Leads, Content Ops, Back-Office, Other"],
  "company_profile": [
    "Industry and business model — one line",
    "Team size and structure — one line",
    "Revenue model or growth stage — one line"
  ],
  "pain_bullets": [
    { "text": "specific actionable pain description", "category": "Reporting | Leads | Content | Back-Office" },
    { "text": "...", "category": "..." },
    { "text": "...", "category": "..." }
  ],
  "security_posture": "1-2 sentences summarizing current security stance based on compliance tier and tool footprint",
  "outcomes_30d": ["concrete, measurable outcome 1", "outcome 2", "outcome 3"],
  "outcomes_90d": ["concrete, measurable outcome 1", "outcome 2", "outcome 3"],
  "constraints": ["specific constraint from off-limits or compliance"],
  "cloud_choice": "GCP | AWS | Azure | None",
  "cloud_reason": "one sentence — why this provider for this client",
  "environments": ["${slug}-ops-dev", "${slug}-ops-prod"],
  "region": "specific region — one sentence on latency or compliance reason",
  "shared_vs_owned": "which components run on DiscoAgents shared infra vs client-owned cloud",
  "automations": [
    {
      "number": "4.1",
      "category": "Reporting | Leads | Content | Back-Office",
      "name": "Short name (3-5 words)",
      "goal": "one sentence goal",
      "triggers": ["system and event that fires this automation"],
      "systems": ["System A", "System B"],
      "mcp_tools": ["specific_tool_name"],
      "security_notes": "one sentence on access scope, read/write boundaries, any risks",
      "effort": "Low | Medium | High"
    },
    { "number": "4.2", "category": "Leads", "name": "...", "goal": "...", "triggers": ["..."], "systems": ["..."], "mcp_tools": ["..."], "security_notes": "...", "effort": "Low" },
    { "number": "4.3", "category": "Back-Office", "name": "...", "goal": "...", "triggers": ["..."], "systems": ["..."], "mcp_tools": ["..."], "security_notes": "...", "effort": "High" }
  ],
  "access_rows": [
    { "area": "Cloud", "resource": "cloud project or org", "access": "service account with limited roles", "who": "CTO / ops owner", "notes": "MFA required" },
    { "area": "DB", "resource": "Supabase project", "access": "mcp_reader credentials", "who": "Dev lead", "notes": "No service-role in MCP" },
    { "area": "Automation", "resource": "n8n instance", "access": "Admin UI + scoped MCP API key", "who": "Ops/tech contact", "notes": "IP allowlist preferred" },
    { "area": "SaaS", "resource": "primary CRM / key tool", "access": "OAuth or scoped read API key", "who": "System admin", "notes": "Read-only where possible" },
    { "area": "Comms", "resource": "Slack or Discord", "access": "Webhook URL only", "who": "Workspace admin", "notes": "For alerts only — no bot write access to production" }
  ]
}`;

return [{ json: { prompt, client: c } }];

// ── Parse Claude response ────────────────────────────────────────────
let b;
try {
  const raw = $input.first().json.content[0].text.trim();
  // Strip markdown fences if Claude added them
  const clean = raw.startsWith('```') ? raw.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '') : raw;
  b = JSON.parse(clean);
} catch (e) {
  // Fallback skeleton so the workflow doesn't halt
  b = {
    stack_maturity: 'Emerging', primary_focus: ['Other'],
    company_profile: ['Company profile — pending review.', '', ''],
    pain_bullets: [{ text: 'Pain details — see linked Client page.', category: 'Other' }],
    security_posture: 'Security posture to be confirmed during discovery call.',
    outcomes_30d: ['30-day outcomes to be confirmed with client.', '', ''],
    outcomes_90d: ['90-day outcomes to be confirmed.', '', ''],
    constraints: ['Constraints to be confirmed.'],
    cloud_choice: 'None', cloud_reason: 'Cloud provider to be determined.',
    environments: ['client-ops-dev', 'client-ops-prod'],
    region: 'Region to be confirmed based on compliance requirements.',
    shared_vs_owned: 'Shared vs client-owned components to be determined during scoping.',
    automations: [
      { number: '4.1', category: 'Other', name: 'Automation 1 TBD', goal: 'TBD', triggers: ['TBD'], systems: ['TBD'], mcp_tools: ['TBD'], security_notes: 'TBD', effort: 'Medium' },
      { number: '4.2', category: 'Other', name: 'Automation 2 TBD', goal: 'TBD', triggers: ['TBD'], systems: ['TBD'], mcp_tools: ['TBD'], security_notes: 'TBD', effort: 'Medium' },
      { number: '4.3', category: 'Other', name: 'Automation 3 TBD', goal: 'TBD', triggers: ['TBD'], systems: ['TBD'], mcp_tools: ['TBD'], security_notes: 'TBD', effort: 'Medium' },
    ],
    access_rows: [
      { area: 'Cloud', resource: 'TBD', access: 'TBD', who: 'TBD', notes: 'MFA required' },
      { area: 'DB', resource: 'Supabase', access: 'mcp_reader', who: 'Dev lead', notes: 'No service-role' },
      { area: 'Automation', resource: 'n8n', access: 'Admin + MCP key', who: 'Ops contact', notes: 'IP gating' },
    ],
  };
}

const c = $('Extract Client Fields').item.json;

// ── Block helpers (Notion API format) ─────────────────────────────────
const rt    = t => [{ type: 'text', text: { content: String(t || ' ') } }];
const h1    = t => ({ object: 'block', type: 'heading_1',          heading_1:          { rich_text: rt(t) } });
const h3    = t => ({ object: 'block', type: 'heading_3',          heading_3:          { rich_text: rt(t) } });
const para  = t => ({ object: 'block', type: 'paragraph',          paragraph:          { rich_text: rt(t) } });
const bul   = t => ({ object: 'block', type: 'bulleted_list_item', bulleted_list_item: { rich_text: rt(t) } });
const todo  = (t, checked = false) => ({ object: 'block', type: 'to_do', to_do: { rich_text: rt(t), checked } });
const call  = (t, emoji = 'ℹ️') => ({ object: 'block', type: 'callout', callout: { rich_text: rt(t), icon: { type: 'emoji', emoji } } });
const div   = () => ({ object: 'block', type: 'divider', divider: {} });

// Security level map (intake value → Blueprint DB select option)
const secMap = {
  'None / informal only': 'Informal',
  'Basic: strong auth, least privilege, audit logs': 'Basic Controls',
  'Formal: SOC2 / ISO / GDPR / other': 'Formal (SOC2/ISO/GDPR)',
};
const secLevel = secMap[c.compliance] || 'Informal';

// Tool list from intake properties
const toolLines = [
  c.tools_crm     && `CRM: ${c.tools_crm}`,
  c.tools_pm      && `Project mgmt: ${c.tools_pm}`,
  c.tools_comms   && `Comms: ${c.tools_comms}`,
  c.tools_ads     && `Marketing / ads: ${c.tools_ads}`,
  c.tools_email   && `Email automation: ${c.tools_email}`,
  c.tools_billing && `Billing / finance: ${c.tools_billing}`,
  c.tools_data    && `Data / storage: ${c.tools_data}`,
  c.automation    && `Automation platforms: ${c.automation}`,
  c.tools_other   && `Other: ${c.tools_other}`,
].filter(Boolean);

// ── SECTION 1 + 2: Current State + Target Outcomes ───────────────────
const s12 = [
  call('Auto-generated from intake. Review and enrich before sharing with client.', '🤖'),
  div(),
  h1('1. Current State (Snapshot)'),
  h3('Company Profile'),
  ...b.company_profile.filter(Boolean).map(bul),
  h3('Systems in Play'),
  ...(toolLines.length ? toolLines.map(bul) : [para('No tools specified in intake.')]),
  h3('Current Pain Points'),
  ...b.pain_bullets.map(p => bul(`[${p.category}] ${p.text}`)),
  h3('Security Posture'),
  para(b.security_posture),
  div(),
  h1('2. Target Outcomes (30–90 Days)'),
  h3('30-Day Outcomes'),
  ...b.outcomes_30d.filter(Boolean).map(bul),
  h3('90-Day Outcomes'),
  ...b.outcomes_90d.filter(Boolean).map(bul),
  h3('Constraints / Non-Negotiables'),
  ...(b.constraints.length ? b.constraints.map(bul) : [para(c.off_limits || 'None specified.')]),
  div(),
];

// ── SECTION 3: Infra Stack ────────────────────────────────────────────
const s3 = [
  h1('3. Recommended Infra Stack'),
  h3('3.1 Cloud & Environments'),
  bul(`Cloud provider: ${b.cloud_choice}`),
  bul(`Reason: ${b.cloud_reason}`),
  bul(`Environments: ${b.environments.join(', ')}`),
  bul(`Region: ${b.region}`),
  bul(`Shared vs client-owned: ${b.shared_vs_owned}`),
  h3('3.2 Core Services'),
  para('[shared] = DiscoAgents managed infra   [client] = provisioned in client cloud account'),
  bul('[shared] n8n — Automation orchestration. Scoped MCP API key; editor access behind IP allowlist or VPN.'),
  bul('[client] Supabase / Postgres — Ops DB + analytics views. mcp_reader role only; service-role never used in MCP or automation.'),
  bul('[shared] Anthropic Claude — AI enrichment and decision logic in workflows. Key scoped to DiscoAgents org.'),
  bul('[client] Google Workspace / SSO — Identity and access control for all ops tooling. MFA enforced for all admin accounts.'),
  bul('[shared] Discord — Internal ops alerts. Webhook URL only; no bot write access to production data.'),
  div(),
];

// ── SECTION 4: Priority Automations ──────────────────────────────────
const s4 = [h1('4. Priority Automations (v1)')];
for (const a of (b.automations || []).slice(0, 3)) {
  s4.push(
    h3(`${a.number} [${a.category}] – ${a.name}  ·  Effort: ${a.effort}`),
    bul(`Goal: ${a.goal}`),
    bul(`Trigger: ${(a.triggers || []).join('; ')}`),
    bul(`Systems involved: ${(a.systems || []).join(', ')}`),
    bul(`MCP tools required: ${(a.mcp_tools || []).join(', ')}`),
    bul(`Security: ${a.security_notes}`),
  );
}
s4.push(
  div(),
  call('v1 limit: 3 automations buildable in 30 days. Add v2 automations only after these are live and stable.', '⚠️'),
  div(),
);

// ── SECTION 5 + 6: Security + Implementation Plan ────────────────────
const autoName = i => (b.automations && b.automations[i]) ? b.automations[i].name : `Automation ${i + 1} TBD`;

const s56 = [
  h1('5. Access & Security Requirements'),
  h3('Access Checklist'),
  ...(b.access_rows || []).map(r => bul(`[${r.area}] ${r.resource} — ${r.access} | Provided by: ${r.who} | ${r.notes}`)),
  h3('Security Level Recap'),
  bul(`Compliance tier: ${secLevel}`),
  bul('No master keys or service-role tokens in MCP. Scoped roles only: mcp_reader for DB, page-level tokens for social, limited n8n API key.'),
  bul('Allow-lists enforced at every boundary: POSTGRES_ALLOWED_TABLES for DB, n8n workflow IDs, SOCIAL_ALLOWED_PLATFORMS.'),
  bul('All MCP tool calls produce a JSON-lines audit record in .logs/mcp-audit.log (SHA-256 args hash, server, status).'),
  bul('Human approval gates required before: terraform apply, git push to prod, outbound Twilio calls/SMS, billing changes, DNS changes, auth DB access.'),
  div(),
  h1('6. 30-Day Implementation Plan'),
  h3('Week 1 – Foundation'),
  todo('Provision cloud project(s), service accounts with least-privilege IAM roles'),
  todo('Deploy Supabase — run 001_mcp_reader_role.sql, grant SELECT on relevant tables, set MCP_DB_URL + POSTGRES_ALLOWED_TABLES'),
  todo('Deploy n8n (dev + prod) — set MCP_API_KEY, configure n8n credential for Notion and Anthropic'),
  todo('Import and activate client-intake-onboarding.json (intake pipeline → Notion → Discord)'),
  todo('Import and activate notion-client-blueprint-draft.json (this workflow)'),
  todo('Verify all env vars: ANTHROPIC_API_KEY, NOTION_TOKEN, DISCORD_INTAKE_WEBHOOK_URL, MCP_DB_URL, POSTGRES_ALLOWED_TABLES'),
  h3('Week 2 – Wire Core Automations'),
  todo(`Build Automation 4.1: ${autoName(0)} — full end-to-end with error handling and Discord error alert`),
  todo(`Build Automation 4.2: ${autoName(1)} — full end-to-end`),
  todo('Configure n8n error workflow → Discord channel for all execution failures'),
  todo('Validate mcp_reader read-only boundary (attempt write operation, confirm rejection)'),
  todo('Review audit logs after first live runs — spot-check args_hash and status'),
  h3('Week 3–4 – Hardening & Handoff'),
  todo(`Build Automation 4.3: ${autoName(2)} — full end-to-end`),
  todo('Security review: IAM roles, API key scopes, audit log spot-check, allow-list validation across all MCP servers'),
  todo('Polish client-visible outputs (report formatting, email templates, Notion dashboard views)'),
  todo('Write client runbook: how to trigger, monitor, pause, and escalate each automation'),
  todo('30-min client team walkthrough session'),
  todo('Final sign-off: client approver confirms live automations meet agreed 30-day outcomes'),
  div(),
  call(`Auto-generated from intake (${c.submitted_at ? c.submitted_at.slice(0, 10) : 'date unknown'}). Generated: ${new Date().toISOString().slice(0, 10)}.`, '📋'),
];

return [{
  json: {
    s12:              JSON.stringify({ children: s12 }),
    s3:               JSON.stringify({ children: s3 }),
    s4:               JSON.stringify({ children: s4 }),
    s56:              JSON.stringify({ children: s56 }),
    blueprint_title:  `${c.company_name} – Ops & Infra Blueprint v1`,
    stack_maturity:   b.stack_maturity,
    primary_focus:    b.primary_focus,
    security_level:   secMap[c.compliance] || 'Informal',
    client_page_id:   c.page_id,
    client:           c,
  }
}];
